#include<bits/stdc++.h>
using namespace std;
int main()
{
   int n;
   cin>>n;
   int a[n],b[n],ans=-INT_MAX;
   for(int i=0;i<n;i++)
   {
       cin>>a[i];
       if(i==0) 
	   {
	   	    b[i]=a[i];
	   }
       else 
	   {
	   	    b[i]=max(a[i],b[i-1]+a[i]);
	   }
       ans=max(ans,b[i]);
   }
   cout<<ans;
   return 0;
}
